import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.Pywvta2k.js";const u=JSON.parse('{"title":"证治汇补","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/11-李用粹（证治汇补）.md","filePath":"tcm-data/04-明清/11-李用粹（证治汇补）.md","lastUpdated":1781084559000}'),o={name:"tcm-data/04-明清/11-李用粹（证治汇补）.md"};function n(i,t,s,d,h,c){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="证治汇补" tabindex="-1">证治汇补 <a class="header-anchor" href="#证治汇补" aria-label="Permalink to &quot;证治汇补&quot;">​</a></h1><blockquote><p>李用粹（1662-1722年），上海人 清代辨证施治的系统化者 代表作：《证治汇补》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字修之，号惺庵</li><li><strong>经历</strong>：上海名医，精通内、外、妇、儿各科</li><li><strong>代表作</strong>：《证治汇补》8卷</li><li><strong>学术地位</strong>：<strong>中医辨证论治的系统化集成者</strong></li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-辨证汇通" tabindex="-1">1. 辨证汇通 <a class="header-anchor" href="#_1-辨证汇通" aria-label="Permalink to &quot;1. 辨证汇通&quot;">​</a></h3><p>李用粹将各家辨证方法汇为一炉：</p><table tabindex="0"><thead><tr><th style="text-align:left;">辨证方法</th><th style="text-align:left;">在他书中的位置</th></tr></thead><tbody><tr><td style="text-align:left;">八纲辨证</td><td style="text-align:left;">卷首总纲</td></tr><tr><td style="text-align:left;">脏腑辨证</td><td style="text-align:left;">各论之首</td></tr><tr><td style="text-align:left;">六经辨证</td><td style="text-align:left;">伤寒篇</td></tr><tr><td style="text-align:left;">卫气营血</td><td style="text-align:left;">温热篇</td></tr></tbody></table><h3 id="_2-证治八法" tabindex="-1">2. 证治八法 <a class="header-anchor" href="#_2-证治八法" aria-label="Permalink to &quot;2. 证治八法&quot;">​</a></h3><blockquote><p><strong>「治病八法：汗、吐、下、和、温、清、补、消。」</strong></p></blockquote><p>这八法是后世中医教材的标准分类。</p><hr><h2 id="三、经典名言" tabindex="-1">三、经典名言 <a class="header-anchor" href="#三、经典名言" aria-label="Permalink to &quot;三、经典名言&quot;">​</a></h2><blockquote><p><strong>「治病八法：汗、吐、下、和、温、清、补、消。」</strong></p></blockquote><blockquote><p><strong>「辨证者，辨其阴阳表里虚实寒热也。」</strong></p></blockquote><blockquote><p><strong>「汇各家之长，补一己之短。」</strong></p></blockquote><hr><h2 id="四、对后世的影响" tabindex="-1">四、对后世的影响 <a class="header-anchor" href="#四、对后世的影响" aria-label="Permalink to &quot;四、对后世的影响&quot;">​</a></h2><ul><li>《证治汇补》是清代最系统的临床手册</li><li>现代《中医内科学》教材的体例受其影响</li><li>八法分类成为中医治法标准</li></ul><hr><p><em>本条目为精简框架版。</em></p>',23)])])}const b=e(o,[["render",n]]);export{u as __pageData,b as default};
